const cfg = $('CONFIG').item.json;
const inp = $('PREPARE INPUT').item.json;

const provider = (cfg.AGENT_RESEARCHER_PROVIDER || 'anthropic').toLowerCase();
const model = cfg.AGENT_RESEARCHER_MODEL || 'claude-sonnet-4-6';
const modelKey = provider === 'google' ? 'google_model' : provider === 'mistral' ? 'mistral_model' : 'anthropic_model';

return [{
  json: {
    llm_provider: provider,
    [modelKey]: model,
    response_format: 'json',
    max_tokens: 4000,
    temperature: 0.4,
    systemPrompt: 'You are a research editor and content strategist. Analyse the brief and produce a structured article outline a writer can follow precisely. Return ONLY a valid JSON object, no markdown, no code fences.',
    userPrompt: 'Brief: ' + inp.prompt + '\n\nTone guide:\n' + inp.tone_guide + '\n\nStyle guide:\n' + inp.style_guide + '\n\nReturn a JSON object with these exact fields:\n- title (string)\n- focus_keyword (string)\n- angle (one-sentence article thesis)\n- h2_sections (array of {heading: string, key_points: string[], notes: string})\n- image_subject (one sentence visual scene for featured image)\n- affiliate_flag: if the article touches products or services that have affiliate programmes, write a short plain-English description of the opportunities (e.g. "Copyscape pay-per-search affiliate — link to plans page"). If none, use the string "none".\n- tags (string[])\n\nReturn ONLY valid JSON, no markdown.'
  }
}];

const rawText = $input.item.json.llm_response;
if (!rawText) throw new Error('Researcher returned empty response');

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

try {
  const outline = JSON.parse(cleaned);
  const inp = $('PREPARE INPUT').item.json;
  return [{
    json: {
      outline,
      prompt: inp.prompt,
      tone_guide: inp.tone_guide,
      style_guide: inp.style_guide,
      category_id: inp.category_id,
    }
  }];
} catch (e) {
  throw new Error('Researcher outline could not be parsed as JSON. Raw: ' + rawText.substring(0, 300));
}

const prediction = $input.item.json.predictions[0];
const base64 = prediction.bytesBase64Encoded;
const mimeType = prediction.mimeType || 'image/png';
const focusKeyword = $('PARSE OUTLINE').item.json.outline.focus_keyword || 'featured';
const slug = focusKeyword.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/, '');
const filename = slug + '.png';
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(base64, 'base64'),
  filename,
  mimeType
);
return [{ json: { image_filename: filename }, binary: { data: binaryData } }];

// Collect posts — HTTP Request v4 splits array responses into separate items
const allItems = $input.all();
const posts = allItems.map(function(item) { return item.json; }).filter(function(p) { return p && p.link; });

const cfg = $('CONFIG').item.json;
const inp = $('PREPARE INPUT').item.json;
const outlineData = $('PARSE OUTLINE').item.json;
const outline = outlineData.outline;

const flagRaw = (inp.enable_internal_links !== undefined && inp.enable_internal_links !== '')
  ? String(inp.enable_internal_links).toLowerCase()
  : String(cfg.ENABLE_INTERNAL_LINKS || 'true').toLowerCase();
const enabled = flagRaw === 'true';

let internalLinks = [];

if (enabled && posts.length > 0) {
  const stopwords = new Set(['a','an','the','and','or','in','on','at','to','for','of','with','how','what','why','is','are','was','were','be','been','being','have','has','had','do','does','did','will','would','could','should','may','might','that','this','these','those','it','its','from','by','as','but','not','your','my','our','their','we','you','i','he','she','they','about','which','can','into','more','some','than','then','there','when','where','who','all','also','just','like','over','after','before','using','use','used']);

  function tokenise(str) {
    return String(str || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').split(/\s+/).filter(function(w) { return w.length > 2 && !stopwords.has(w); });
  }

  const signals = [outline.focus_keyword || '', outline.title || ''].concat(outline.tags || []);
  const signalTokens = new Set(signals.reduce(function(acc, s) { return acc.concat(tokenise(s)); }, []));

  const scored = posts.map(function(post) {
    const titleText = post.title && typeof post.title === 'object' ? (post.title.rendered || '') : (post.title || '');
    const cleanTitle = titleText.replace(/<[^>]+>/g, '');
    const score = tokenise(cleanTitle).filter(function(t) { return signalTokens.has(t); }).length;
    return { title: cleanTitle, url: post.link || '', score: score };
  }).filter(function(p) { return p.score > 0; })
    .sort(function(a, b) { return b.score - a.score; })
    .slice(0, 5);

  internalLinks = scored.map(function(p) { return { title: p.title, url: p.url }; });
}

return [{ json: Object.assign({}, outlineData, { internal_links: internalLinks }) }];

const cfg = $('CONFIG').item.json;
const outline = $input.item.json.outline;
const toneGuide = $input.item.json.tone_guide;
const styleGuide = $input.item.json.style_guide;
const internalLinks = $input.item.json.internal_links || [];

const provider = (cfg.AGENT_WRITER_PROVIDER || 'google').toLowerCase();
const model = cfg.AGENT_WRITER_MODEL || 'gemini-3.5-flash';
const modelKey = provider === 'google' ? 'google_model' : provider === 'mistral' ? 'mistral_model' : 'anthropic_model';

const sections = (outline.h2_sections || []).map(function(s) {
  return '## ' + s.heading + '\nKey points: ' + (s.key_points || []).join('; ') + '\nNotes: ' + (s.notes || 'none');
}).join('\n\n');

const internalLinksBlock = internalLinks.length > 0
  ? '\n\nINTERNAL LINKS — where contextually appropriate, naturally weave links to these existing posts into the article body using HTML anchor tags. Only link where the context genuinely invites it; do not force them or mention them out of place:\n' + internalLinks.map(function(l) { return '- ' + l.title + ': ' + l.url; }).join('\n')
  : '';

return [{
  json: {
    llm_provider: provider,
    [modelKey]: model,
    response_format: 'text',
    max_tokens: 12000,
    temperature: 0.7,
    systemPrompt: 'You are a skilled content writer. Write in the exact voice described in the tone guide. Follow the style guide for structure and formatting. Write the article body directly in HTML — do not wrap output in JSON or code fences.',
    userPrompt: 'Write a full article draft based on the outline below.\n\nTONE GUIDE:\n' + toneGuide + '\n\nSTYLE GUIDE:\n' + styleGuide + '\n\nOUTLINE:\nTitle: ' + outline.title + '\nAngle: ' + outline.angle + '\nFocus keyword: ' + outline.focus_keyword + '\n\nSections:\n' + sections + internalLinksBlock + '\n\nWrite the full HTML article body using <h2>, <p>, <ul>/<li> tags. After the article body, add a line reading exactly "EXCERPT:" followed by a two-sentence summary paragraph.\n\nWrite only article content — no JSON, no code fences, no preamble.'
  }
}];

const rawText = $input.item.json.llm_response;
if (!rawText) throw new Error('Reviewer returned empty response');

const cleaned = rawText
  .replace(/^```[a-z]*\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

const sepIdx = cleaned.indexOf('---JSON---');

let content, meta;

if (sepIdx !== -1) {
  content = cleaned.substring(0, sepIdx).trim();

  const firstHtmlIdx = content.search(/<(p|h[1-6]|ul|ol|pre|blockquote)[\s>]/i);
  if (firstHtmlIdx > 0) content = content.substring(firstHtmlIdx);

  const jsonPart = cleaned.substring(sepIdx + '---JSON---'.length).trim();
  try {
    meta = JSON.parse(jsonPart);
  } catch (e) {
    const outlineData = $('PARSE OUTLINE').first().json.outline || {};
    const extractStr = (field) => {
      const m = jsonPart.match(new RegExp('"' + field + '"\\s*:\\s*"((?:[^\\"]|\\\\.)*)"'));
      return m ? m[1] : null;
    };
    const tagsMatch = jsonPart.match(/"tags"\s*:\s*\[([^\]]*)\]/);
    let tags = [];
    if (tagsMatch) {
      const rawTags = tagsMatch[1].match(/"([^"]*)"/g);
      if (rawTags) tags = rawTags.map(t => t.replace(/"/g, ''));
    }
    meta = {
      title:           extractStr('title')           || outlineData.title || 'Untitled',
      excerpt:         extractStr('excerpt')         || '',
      tags:            tags.length ? tags            : (outlineData.tags || []),
      seo_title:       extractStr('seo_title')       || outlineData.title || '',
      seo_description: extractStr('seo_description') || '',
      focus_keyword:   extractStr('focus_keyword')   || outlineData.focus_keyword || '',
      image_subject:   extractStr('image_subject')   || outlineData.image_subject || '',
      affiliate_flag:  extractStr('affiliate_flag')  || 'none'
    };
  }
} else {
  try {
    const article = JSON.parse(cleaned);
    content = article.content;
    meta = article;
  } catch(e) {
    const outlineData = $('PARSE OUTLINE').first().json.outline || {};
    const draftExcerpt = $('BUILD REVIEW PROMPT').first().json._draft_excerpt || '';
    content = cleaned;
    meta = {
      title: outlineData.title || 'Untitled',
      excerpt: draftExcerpt,
      tags: outlineData.tags || [],
      seo_title: outlineData.title || '',
      seo_description: '',
      focus_keyword: outlineData.focus_keyword || '',
      image_subject: outlineData.image_subject || '',
      affiliate_flag: outlineData.affiliate_flag || 'none'
    };
  }
}

function sanitiseHtml(html) {
  if (!html) return '';
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<iframe[\s\S]*?<\/iframe>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<object[\s\S]*?<\/object>/gi, '')
    .replace(/<embed[^>]*>/gi, '')
    .replace(/<form[\s\S]*?<\/form>/gi, '')
    .replace(/ on[a-z]+\s*=\s*"[^"]*"/gi, '')
    .replace(/ on[a-z]+\s*=\s*'[^']*'/gi, '')
    .replace(/ on[a-z]+\s*=\s*[^\s>]*/gi, '')
    .replace(/(href|src)\s*=\s*"javascript:[^"]*"/gi, '$1="#"')
    .replace(/(href|src)\s*=\s*'javascript:[^']*'/gi, "$1='#'");
}

function truncateAtWord(str, maxLen) {
  if (!str) return '';
  const s = String(str).trim();
  if (s.length <= maxLen) return s;
  const cut = s.substring(0, maxLen);
  const lastSpace = cut.lastIndexOf(' ');
  return (lastSpace > 0 ? cut.substring(0, lastSpace) : cut) + '…';
}

function normaliseAffiliateFlag(val) {
  if (val === true || val === 'true') return 'Affiliate opportunities present — check outline notes for details';
  if (!val || val === false || val === 'false') return 'none';
  return String(val);
}

const safeContent = sanitiseHtml(content);
const seoTitle = truncateAtWord(meta.seo_title || meta.title || '', 60);
const seoDesc  = truncateAtWord(meta.seo_description || '', 155);

return [{ json: {
  title:           meta.title,
  content:         safeContent,
  excerpt:         meta.excerpt,
  tags:            meta.tags,
  seo_title:       seoTitle,
  seo_description: seoDesc,
  focus_keyword:   meta.focus_keyword || (meta.tags && meta.tags[0]),
  image_subject:   meta.image_subject,
  affiliate_flag:  normaliseAffiliateFlag(meta.affiliate_flag)
}}];

const tagIds = $input.all().map(item => {
  const r = item.json;
  return r.id || (r.data && r.data.term_id) || null;
}).filter(id => id !== null && id !== undefined && id !== 0);
return [{ json: { tag_ids: tagIds } }];

const calls = [
  { label: 'researcher', data: $('CALL RESEARCHER').first().json },
  { label: 'writer',     data: $('CALL WRITER').first().json },
  { label: 'reviewer',  data: $('CALL REVIEWER').first().json },
];

let totalInput  = 0;
let totalOutput = 0;
let totalCost   = 0;
let hasCost     = false;
const breakdown = [];

for (const { label, data } of calls) {
  const inp  = data._input_tokens  ?? 0;
  const out  = data._output_tokens ?? 0;
  const cost = data._estimated_cost_usd ?? null;
  totalInput  += inp;
  totalOutput += out;
  if (cost !== null) {
    totalCost += cost;
    hasCost = true;
  }
  breakdown.push({
    agent:              label,
    model:              data.model_used    || '?',
    provider:           data.provider_used || '?',
    input_tokens:       inp,
    output_tokens:      out,
    estimated_cost_usd: cost,
  });
}

return [{
  json: {
    ...$input.first().json,
    _llm_total_input_tokens:  totalInput,
    _llm_total_output_tokens: totalOutput,
    _llm_total_cost_usd:      hasCost ? totalCost : null,
    _llm_breakdown:           breakdown,
  }
}];

