const stageMap = {
  'CALL RESEARCHER': 'Outline Researcher',
  'CALL WRITER': 'Draft Writer',
  'CALL REVIEWER': 'Article Reviewer'
};

const stage = stageMap[$prevNode.name] || $prevNode.name;
const errorMsg = typeof $json.error === 'object'
  ? ($json.error.message || JSON.stringify($json.error))
  : String($json.error || 'Unknown error');

const channel = $('CONFIG').item.json.SLACK_CHANNEL;

return [{
  json: {
    stage,
    error: errorMsg,
    channel,
    slack_text: '⚠️ *Pipeline failure* — stage: *' + stage + '*\nError: ' + errorMsg + '\n_Workflow: trigger.wordpress_article_publisher_'
  }
}];
